// flipbook.min.js - 翻书轮播独立组件
(function(){
    // 样式字符串
    const styleText = `
        *{-webkit-user-select:none;-moz-user-select:none;-ms-user-select:none;user-select:none;-webkit-tap-highlight-color:transparent}
        :root{--bg-color:#d0d0d0;--text-color:#222}
        @media(prefers-color-scheme:dark){:root{--bg-color:#1a1a1a;--text-color:#fff}body,html{background-image:linear-gradient(45deg,rgba(255,255,255,0.1) 25%,transparent 25%),linear-gradient(-45deg,rgba(255,255,255,0.1) 25%,transparent 25%),linear-gradient(45deg,transparent 75%,rgba(255,255,255,0.1) 75%),linear-gradient(-45deg,transparent 75%,rgba(255,255,255,0.1) 75%);background-size:8px 8px}}
        body,html{margin:0;padding:0;width:100vw;height:100vh;background-color:var(--bg-color);overflow:hidden;display:flex;justify-content:center;align-items:center;touch-action:none}
        .flipbook-container{width:100%;height:100%;display:flex;justify-content:center;align-items:center;position:relative}
        canvas{position:absolute!important;z-index:100!important;pointer-events:none!important}
        .nav-button{position:absolute;top:50%;transform:translateY(-50%);display:flex;justify-content:center;align-items:center;cursor:pointer;z-index:1000002!important;font-size:36px;color:white;user-select:none;pointer-events:auto!important;text-shadow:2px 2px 8px rgba(0,0,0,0.8);background:transparent}
        .nav-button:hover{text-shadow:2px 2px 12px rgba(0,0,0,1)}
        .prev-button{left:15px}
        .next-button{right:15px}
        .click-area{position:absolute!important;background:transparent!important;cursor:pointer!important;pointer-events:auto!important;display:block!important;z-index:1000000!important;border:none!important}
        .title-display{position:absolute!important;color:white!important;padding:8px 12px!important;border-radius:4px!important;font-size:12px!important;text-align:center!important;width:35%!important;max-width:35%!important;overflow:hidden!important;text-overflow:ellipsis!important;white-space:nowrap!important;pointer-events:none!important;display:block!important;z-index:1000001!important;transition:opacity 0.4s ease-in-out!important;opacity:1!important;text-shadow:2px 2px 6px rgba(0,0,0,0.8);font-weight:bold!important}
        .left-area{left:10%!important;width:35%!important;height:70%!important;top:15%!important}
        .left-title{left:10%!important;top:87%!important;width:35%!important}
        .right-area{right:10%!important;width:35%!important;height:70%!important;top:15%!important}
        .right-title{right:10%!important;top:87%!important;width:35%!important}
        .click-container{position:absolute;top:0;left:0;width:100%;height:100%;z-index:999999!important;pointer-events:none}
        #zim-stage,#zim-frame{background-color:transparent!important}
    `;

    // 动态加载脚本
    function loadScript(src) {
        return new Promise((resolve, reject) => {
            const script = document.createElement('script');
            script.src = src;
            script.onload = resolve;
            script.onerror = reject;
            document.head.appendChild(script);
        });
    }

    // 全局翻书创建函数
    window.createFlipBook = async function(containerId, items) {
        // 确保容器存在
        let container = document.getElementById(containerId);
        if (!container) {
            container = document.createElement('div');
            container.id = containerId;
            container.className = 'flipbook-container';
            document.body.appendChild(container);
        } else {
            container.innerHTML = ''; // 清空
            container.className = 'flipbook-container';
        }

        // 注入样式
        if (!document.getElementById('flipbook-style')) {
            const styleEl = document.createElement('style');
            styleEl.id = 'flipbook-style';
            styleEl.textContent = styleText;
            document.head.appendChild(styleEl);
        }

        // 等待 ZIM 库加载
        if (typeof createjs === 'undefined') {
            await loadScript('https://zimjs.org/cdn/1.3.3/createjs.js');
        }
        if (typeof Frame === 'undefined') {
            await loadScript('https://zimjs.org/cdn/nft/01/zim.js');
        }
        if (typeof Icon === 'undefined') {
            await loadScript('https://zimjs.org/cdn/icon6.js');
        }

        // 创建导航按钮和点击区域
        const prevBtn = document.createElement('div');
        prevBtn.className = 'nav-button prev-button';
        prevBtn.textContent = '‹';
        const nextBtn = document.createElement('div');
        nextBtn.className = 'nav-button next-button';
        nextBtn.textContent = '›';
        const clickContainer = document.createElement('div');
        clickContainer.className = 'click-container';
        container.appendChild(prevBtn);
        container.appendChild(nextBtn);
        container.appendChild(clickContainer);

        // 创建左右点击区和标题栏
        const leftArea = document.createElement('div');
        leftArea.className = 'click-area left-area';
        const rightArea = document.createElement('div');
        rightArea.className = 'click-area right-area';
        const leftTitle = document.createElement('div');
        leftTitle.className = 'title-display left-title';
        const rightTitle = document.createElement('div');
        rightTitle.className = 'title-display right-title';
        clickContainer.appendChild(leftArea);
        clickContainer.appendChild(rightArea);
        clickContainer.appendChild(leftTitle);
        clickContainer.appendChild(rightTitle);

        // 数据相关变量
        let imageData = items;
        let leftPageIndex = 0;
        let rightPageIndex = 1;
        let currentPage = 1;
        const totalPages = Math.ceil(imageData.length / 2);
        let book = null;
        let autoPlayInterval = null;
        let autoPlayDirection = 1;
        const autoPlayIntervalTime = 5000;

        function fadeOutTitles() {
            leftTitle.style.opacity = '0';
            rightTitle.style.opacity = '0';
        }
        function fadeInTitles() {
            setTimeout(() => {
                leftTitle.style.opacity = '1';
                rightTitle.style.opacity = '1';
            }, 500);
        }
        function updateTitlesContent() {
            if (leftPageIndex >= 0 && leftPageIndex < imageData.length) {
                const left = imageData[leftPageIndex];
                leftTitle.textContent = left.title || '无标题';
                leftArea.dataset.link = left.url || '#';
                leftArea.dataset.item = JSON.stringify(left);
                leftArea.style.display = 'block';
                leftTitle.style.display = 'block';
            } else {
                leftArea.style.display = 'none';
                leftTitle.style.display = 'none';
            }
            if (rightPageIndex >= 0 && rightPageIndex < imageData.length) {
                const right = imageData[rightPageIndex];
                rightTitle.textContent = right.title || '无标题';
                rightArea.dataset.link = right.url || '#';
                rightArea.dataset.item = JSON.stringify(right);
                rightArea.style.display = 'block';
                rightTitle.style.display = 'block';
            } else {
                rightArea.style.display = 'none';
                rightTitle.style.display = 'none';
            }
        }
        function updateAreasData(withFade) {
            if (withFade) {
                fadeOutTitles();
                setTimeout(() => { updateTitlesContent(); fadeInTitles(); }, 300);
            } else {
                updateTitlesContent();
                leftTitle.style.opacity = '1';
                rightTitle.style.opacity = '1';
            }
        }

        function handleClick(e) {
            const link = e.target.dataset.link;
            const itemData = e.target.dataset.item;
            if (itemData) {
                try { window.item = JSON.parse(itemData); } catch(e) {}
            }
            if (link && link !== '#') {
                window.open(link, '_blank');
            }
            e.stopPropagation();
            e.preventDefault();
        }
        leftArea.addEventListener('click', handleClick);
        rightArea.addEventListener('click', handleClick);
        leftArea.addEventListener('touchend', (e) => { e.preventDefault(); handleClick(e); });
        rightArea.addEventListener('touchend', (e) => { e.preventDefault(); handleClick(e); });

        updateAreasData(false);

        // ZIM 翻书逻辑
        const assets = { font: "reuben", src: "https://assets.codepen.io/2104200/Reuben.otf" };
        const width = 1024;
        const height = 868;
        const frame = new Frame(FIT, width, height, "rgba(0,0,0,0)", assets);
        frame.on("ready", function() {
            const stage = frame.stage;
            const imageUrls = imageData.map(item => item.img);
            const imageTitles = imageData.map(item => item.title || '');
            const pageBackgroundColors = ["#f8f8f8","#f0f0f0","#e8e8e8","#f5f5f5","#fafafa","#f2f2f2"];
            const imageContainerBgColor = "#ffffff";
            STYLE = { Page: { width: width/2, height: height } };
            const pages = [];
            for (let i = 0; i < imageUrls.length; i++) {
                const page = new Page();
                page.color = pageBackgroundColors[i % pageBackgroundColors.length];
                const imgContainer = new Container({ width: 500, height: 750, backgroundColor: imageContainerBgColor, corner: 5 }).center(page);
                const mask = new Shape({ width: 500, height: 750, color: clear, corner: 5 });
                imgContainer.mask = mask;
                const bitmap = new createjs.Bitmap(imageUrls[i]);
                bitmap.image.onload = function() {
                    const scale = Math.min(460/this.width, 680/this.height);
                    bitmap.scaleX = bitmap.scaleY = scale;
                    bitmap.x = (0 - this.width*scale)/2;
                    bitmap.y = (0 - this.height*scale)/2;
                    imgContainer.addChild(bitmap);
                    new Label({ text: "- "+(i+1)+" -", size:20, color: gray.darken(0.3) }).alp(0.7).pos(0,30, CENTER, BOTTOM, page);
                    stage.update();
                };
                bitmap.image.onerror = function() {
                    new Label({ text: imageTitles[i] || `图片 ${i+1}`, size:24, color: gray, textAlign: "center" }).center(imgContainer);
                    new Label({ text: "- "+(i+1)+" -", size:20, color: gray.darken(0.3) }).alp(0.7).pos(0,30, CENTER, BOTTOM, page);
                    stage.update();
                };
                pages.push(page);
            }
            let bookPages = [...pages];
            if (bookPages.length % 2 !== 0) bookPages.push(new Page());
            book = new Book({
                width: bookPages[0].width*2, height: bookPages[0].height, pages: bookPages,
                startPage: 1, backgroundColor: null, drag: true, edge: 100, flipTime: 800,
                mouse: true, touch: true, swipe: true, swipeDistance: 50, allowQuickSwipe: true, doublePage: true
            }).center();

            function performAutoPageTurn() {
                if (autoPlayDirection === 1) {
                    if (currentPage < totalPages) nextBtn.click();
                    else { autoPlayDirection = -1; prevBtn.click(); }
                } else {
                    if (currentPage > 1) prevBtn.click();
                    else { autoPlayDirection = 1; nextBtn.click(); }
                }
            }
            function startAutoPlay() {
                if (autoPlayInterval) clearInterval(autoPlayInterval);
                autoPlayInterval = setInterval(performAutoPageTurn, autoPlayIntervalTime);
            }
            function stopAutoPlay() { if (autoPlayInterval) clearInterval(autoPlayInterval); }
            function resetAutoPlayTimer() {
                if (autoPlayInterval) {
                    clearInterval(autoPlayInterval);
                    autoPlayInterval = setInterval(performAutoPageTurn, autoPlayIntervalTime);
                }
            }

            prevBtn.addEventListener('click', (e) => {
                e.stopPropagation(); e.preventDefault();
                resetAutoPlayTimer();
                if (currentPage > 1) {
                    currentPage--;
                    leftPageIndex = (currentPage-1)*2;
                    rightPageIndex = leftPageIndex+1;
                    updateAreasData(true);
                }
                if (book && book.prevPage) book.prevPage();
            });
            nextBtn.addEventListener('click', (e) => {
                e.stopPropagation(); e.preventDefault();
                resetAutoPlayTimer();
                if (currentPage < totalPages) {
                    currentPage++;
                    leftPageIndex = (currentPage-1)*2;
                    rightPageIndex = leftPageIndex+1;
                    updateAreasData(true);
                }
                if (book && book.nextPage) book.nextPage();
            });
            document.addEventListener('keydown', (e) => {
                if (e.key === 'ArrowRight') {
                    resetAutoPlayTimer();
                    if (currentPage < totalPages) {
                        currentPage++;
                        leftPageIndex = (currentPage-1)*2;
                        rightPageIndex = leftPageIndex+1;
                        updateAreasData(true);
                    }
                    if (book && book.nextPage) book.nextPage();
                }
                if (e.key === 'ArrowLeft') {
                    resetAutoPlayTimer();
                    if (currentPage > 1) {
                        currentPage--;
                        leftPageIndex = (currentPage-1)*2;
                        rightPageIndex = leftPageIndex+1;
                        updateAreasData(true);
                    }
                    if (book && book.prevPage) book.prevPage();
                }
            });
            book.on("change", (e) => {
                resetAutoPlayTimer();
                const zimPage = e.currentPage;
                const ourPage = Math.floor((zimPage-1)/2)+1;
                if (ourPage !== currentPage) {
                    currentPage = ourPage;
                    leftPageIndex = (currentPage-1)*2;
                    rightPageIndex = leftPageIndex+1;
                    updateAreasData(false);
                }
            });
            stage.update();
            setTimeout(startAutoPlay, 3000);
        });
        frame.on("error", (err) => console.error('Frame error:', err));
    };
})();